const saveCustomAgents = (agents: AgentDef[]) => {
  setCustomAgents(agents)
  api()?.setCustomAgents?.(agents)  // Promise not awaited
}

const handleDeleteAgent = (agent: AgentDef) => {
  saveCustomAgents(customAgents().filter((a) => a.id !== agent.id))
  showToast({
    title: language.t("dialog.agents.delete"),
    description: `"${agent.name}" deleted`,
  })
}

ipcMain.handle('get-desktop-custom-agents', () => {
  const store = getStore('desktop-custom-agents')
  return (store.get('agents') as unknown[]) ?? []
})
ipcMain.handle('set-desktop-custom-agents', (_event, agents: unknown[]) => {
  const store = getStore('desktop-custom-agents')
  store.set('agents', agents)
})

if (!loaded()) {
  const a = api()
  if (a?.getCustomAgents) {
    setLoaded(true)
    a.getCustomAgents().then((agents) => {
      setCustomAgents((agents ?? []) as AgentDef[])
    })
  }
}

const hasCompaction = createMemo(() => {
  const sessionID = params.id
  if (!sessionID) return false
  const parts = sync.data.part
  for (const msg of messages()) {
    const msgParts = parts[msg.id]
    if (msgParts?.some((p) => p.type === 'compaction')) return true
  }
  return false
})

